sql:
SELECT turbine_id
FROM wind_turbine_data
WHERE wind_speed_m_s > 10;

SELECT turbine_id, farm_id
FROM turbines
WHERE operational_status = 'operational';

SELECT AVG(active_power_kW) AS AvgActivePower
FROM wind_turbine_data
WHERE turbine_id = 1 AND timestamp BETWEEN '2022-01-01 00:00:00' AND '2022-12-31 23:59:59';

external_knowledge:
- "plagued by storms" metaphorically refers to high-severity, active alerts;
- "major storms" are represented by alerts with 'high' severity;
- "wind farms and the captains steering these farms" correspond to wind farm names, geographical locations, and operators respectively;
- "at least three" indicates a count of alerts that meets or exceeds three.

sql:
SELECT turbine_id
FROM turbines
WHERE manufacturer = 'Turbine Inc.';

SELECT COUNT(turbine_id) AS total_turbines, farm_id
FROM turbines
GROUP BY farm_id;

SELECT *
FROM wind_turbine_data
WHERE active_power_kW < (SELECT AVG(active_power_kW) FROM wind_turbine_data);

SELECT description 
FROM alerts 
WHERE turbine_id = 1 AND alert_severity = 'high';

SELECT COUNT(turbine_id) 
FROM turbines 
WHERE capacity_kW > 1000;

SELECT farm_name
FROM wind_farms
WHERE capacity_MW > (
    SELECT AVG(capacity_MW)
    FROM wind_farms
) AND total_turbines > 15 AND farm_name LIKE 'Wind%';

SELECT turbine_id, COUNT(*) AS total_logs
FROM maintenance_logs
GROUP BY turbine_id;
